// ---------------------------------------------------------------------------
// STYLES — plain CSS properties with semantic tokens only.
// ---------------------------------------------------------------------------

const styles: Record<string, CSSProperties> = {
  queueColumn: {
    height: '100%',
    minHeight: 0,
  },
  queueControls: {
    paddingInline: 'var(--spacing-3)',
    paddingBlock: 'var(--spacing-2)',
  },
  queueScroll: {
    minHeight: 0,
    overflowY: 'auto',
    paddingInline: 'var(--spacing-2)',
    paddingBottom: 'var(--spacing-3)',
  },
  queueEmpty: {
    paddingInline: 'var(--spacing-3)',
    paddingTop: 'var(--spacing-4)',
  },
  // Tabular numerals so stacked SLA countdowns digit-align down the queue.
  slaChip: {
    flexShrink: 0,
    fontVariantNumeric: 'tabular-nums',
  },
  conversationColumn: {
    height: '100%',
    minHeight: 0,
  },
  conversationHeader: {
    paddingInline: 'var(--spacing-4)',
    paddingBlock: 'var(--spacing-3)',
  },
  // height 0 + flexGrow keeps long threads from pushing the pinned composer
  // below the fold (they scroll inside this box); the viewport-tracking
  // minHeight floor keeps the frame tall when the container is auto-sized
  // (520px ≈ page header + conversation header + banner + composer chrome).
  messageScroll: {
    height: 0,
    minHeight: 'max(320px, calc(100dvh - 520px))',
    flexGrow: 1,
    overflowY: 'auto',
    paddingInline: 'var(--spacing-4)',
    paddingBlock: 'var(--spacing-4)',
  },
  messageStream: {
    maxWidth: 720,
  },
  // Amber "team eyes only" surface — deliberately different from the
  // customer-visible message rows around it.
  noteCard: {
    backgroundColor: 'var(--color-background-yellow)',
    borderColor: 'var(--color-border-yellow)',
  },
  composer: {
    paddingInline: 'var(--spacing-4)',
    paddingBlock: 'var(--spacing-3)',
  },
  composerNoteTint: {
    backgroundColor: 'var(--color-background-yellow)',
  },
  railColumn: {
    height: '100%',
    minHeight: 0,
  },
  railScroll: {
    minHeight: 0,
    overflowY: 'auto',
    paddingInline: 'var(--spacing-3)',
    paddingBlock: 'var(--spacing-3)',
  },
  timelineRow: {
    alignItems: 'baseline',
  },
  // Centers the small pulsing dot on the Banner title's first text line —
  // without this the dot hugs the icon slot's top edge.
  bannerDot: {
    display: 'inline-flex',
    alignItems: 'center',
    height: 20,
  },
  // The mailbox-title cell gives way first so header actions never clip.
  headerTitle: {
    minWidth: 0,
  },
  // <=800px: the status/SLA badges drop under the subject so it keeps the
  // full width instead of wrapping one word per line beside them.
  mobileBadgeRow: {
    paddingTop: 'var(--spacing-2)',
  },
  // ~40px touch targets in single-pane mode (size="sm" renders 28px).
  buttonTapTarget: {height: 40},
  iconTapTarget: {width: 40, height: 40},
};

