type FileExt = 'md' | 'sh' | 'json';

interface SkillFile {
  id: string;
  path: string;
  ext: FileExt;
  isExecutable: boolean;
  language: string;
  code: string;
}

// Extension tint vocabulary: .md=blue, .sh=green, .json=yellow.
