// ============= STYLES =============

const styles: Record<string, CSSProperties> = {
  // Sticky bulk-action bar: pinned to the top of the content scroller so
  // it stays visible while the table scrolls underneath. The Toolbar's
  // "section" variant supplies an opaque background.
  actionBar: {
    position: 'sticky',
    top: 0,
    zIndex: 2,
  },
  visuallyHidden: {
    position: 'absolute',
    width: '1px',
    height: '1px',
    margin: '-1px',
    padding: 0,
    overflow: 'hidden',
    clipPath: 'inset(50%)',
    whiteSpace: 'nowrap',
  },
};

// ============= DATA =============

type TicketStatus = 'open' | 'pending' | 'resolved';
type TicketPriority = 'urgent' | 'high' | 'normal';

interface TicketRow extends Record<string, unknown> {
  id: string;
  subject: string;
  category: string;
  requester: string;
  company: string;
  status: TicketStatus;
  priority: TicketPriority;
  assignee: string | null;
  updated: string;
  isArchived: boolean;
}

