// ============= COMPONENTS =============

function DetailCard({detail}: {detail: EventDetail}) {
  if (detail.kind === 'quote') {
    return (
      <Card variant="muted" padding={3}>
        <Text type="body" color="secondary">
          {detail.text}
        </Text>
      </Card>
    );
  }
  return (
    <Card padding={3}>
      <VStack gap={1}>
        <HStack gap={2} vAlign="center">
          <StatusDot variant={detail.dot.variant} label={detail.dot.label} />
          <StackItem size="fill">
            <Text type="body" maxLines={2}>
              {detail.headline}
            </Text>
          </StackItem>
          {detail.tokens.map(token => (
            <Token
              key={token.label}
              label={token.label}
              color={token.color}
              size="sm"
            />
          ))}
        </HStack>
        <Text type="supporting" color="secondary">
          {detail.meta}
        </Text>
      </VStack>
    </Card>
  );
}

function EventRow({
  event,
  isLast,
  isNarrow,
}: {
  event: TimelineEvent;
  isLast: boolean;
  isNarrow: boolean;
}) {
  const timestamp = (
    <Timestamp value={event.time} format="time" color="secondary" />
  );
  return (
    <div style={styles.row}>
      <div style={styles.gutter}>
        <div style={styles.marker}>
          <Icon icon={event.icon} size="sm" color={event.iconColor} />
        </div>
        {!isLast && <div style={styles.connector} />}
      </div>
      <div style={{...styles.body, ...(isLast ? styles.bodyLast : undefined)}}>
        <VStack gap={2}>
          <HStack gap={2} vAlign="center">
            <Avatar name={event.actor} size="xsmall" />
            <StackItem size="fill">
              <VStack gap={0.5}>
                <Text type="body">
                  <Text weight="semibold" color="inherit">
                    {event.actor}
                  </Text>{' '}
                  {event.action}
                </Text>
                {isNarrow && timestamp}
              </VStack>
            </StackItem>
            {!isNarrow && timestamp}
          </HStack>
          {event.detail && <DetailCard detail={event.detail} />}
        </VStack>
      </div>
    </div>
  );
}

export default function TimelineTemplate() {
  const [typeFilter, setTypeFilter] = useState('all');
  const isNarrow = useMediaQuery('(max-width: 640px)');

  // Apply the type filter per day, dropping days that empty out so no
  // orphaned date header renders.
  const visibleDays = useMemo(() => {
    return DAYS.map(day => ({
      ...day,
      events:
        typeFilter === 'all'
          ? day.events
          : day.events.filter(event => event.type === typeFilter),
    })).filter(day => day.events.length > 0);
  }, [typeFilter]);

  const visibleCount = visibleDays.reduce(
    (total, day) => total + day.events.length,
    0,
  );

  const filterControl = (
    <SegmentedControl
      label="Filter events by type"
      value={typeFilter}
      onChange={setTypeFilter}
      size="sm"
      style={isNarrow ? styles.filterTapTarget : undefined}>
      {FILTERS.map(filter => (
        <SegmentedControlItem
          key={filter.value}
          label={filter.label}
          value={filter.value}
        />
      ))}
    </SegmentedControl>
  );

  const titleBlock = (
    <HStack gap={2} vAlign="center">
      <Heading level={1}>Activity</Heading>
      <Text type="supporting" color="secondary">
        checkout-api · {visibleCount} events · last 5 days
      </Text>
    </HStack>
  );

  return (
    <Layout
      height="fill"
      header={
        <LayoutHeader hasDivider>
          {isNarrow ? (
            <VStack gap={2}>
              {titleBlock}
              {filterControl}
            </VStack>
          ) : (
            <HStack gap={3} vAlign="center">
              <StackItem size="fill">{titleBlock}</StackItem>
              {filterControl}
            </HStack>
          )}
        </LayoutHeader>
      }
      content={
        <LayoutContent>
          <div style={styles.feed}>
            {visibleDays.length === 0 ? (
              <EmptyState
                icon={<Icon icon={InboxIcon} size="lg" />}
                title="No events"
                description="Nothing in the last 5 days matches this filter."
              />
            ) : (
              visibleDays.map(day => (
                <div key={day.id}>
                  <div style={styles.dateHeader}>
                    <Text type="label" color="secondary">
                      {day.label}
                    </Text>
                  </div>
                  {day.events.map((event, index) => (
                    <EventRow
                      key={event.id}
                      event={event}
                      isLast={index === day.events.length - 1}
                      isNarrow={isNarrow}
                    />
                  ))}
                </div>
              ))
            )}
          </div>
        </LayoutContent>
      }
    />
  );
}
